insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-3-business-ownership:misc:64af61b1', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A private limited company and a public limited company are basically the same thing — just different sizes.</p><p><strong>✅ The correct idea:</strong> They are fundamentally different. Key differences: (1) a plc can sell shares on the Stock Exchange, an Ltd cannot; (2) a plc needs £50,000 minimum share capital; (3) a plc can be taken over by hostile buyers, an Ltd cannot without shareholder consent; (4) a plc faces more public scrutiny of its finances.</p>", "question": "Which of the following is a fundamental legal difference between a private limited company and a public limited company?", "options": ["An Ltd requires more share capital to set up than a plc", "Only a plc has shareholders", "A plc can sell shares on the Stock Exchange, whereas an Ltd cannot", "An Ltd is legally required to publish full annual accounts, but a plc is not"]}'::jsonb, '{"answer": 2, "explain": "The card lists key differences including that a plc can sell shares on the Stock Exchange while an Ltd cannot, showing they are fundamentally different structures, not just different sizes of the same thing."}'::jsonb),
('business:1-3-business-ownership:misc:405048f5', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When answering about disadvantages of a limited company, it is fine to say ''it is expensive'' or ''there is a lot of paperwork''.</p><p><strong>✅ The correct idea:</strong> These are too vague for the examiner. You must state specifically WHAT is expensive and WHY, and explain the business-facing impact. For example: ''The requirement to submit detailed accounts to Companies House (U) means Tom and Amir spend time on administration (APP) that could be used for customer service — their priority (AN).''</p>", "question": "According to exam guidance, why is stating ''it is expensive'' as a disadvantage of a limited company insufficient for marks?", "options": ["It is too vague — say specifically what is expensive and why", "Because expense is never actually a disadvantage of limited companies", "Because examiners only accept numerical answers", "Because ''expensive'' is a banned word in GCSE Business exams"]}'::jsonb, '{"answer": 0, "explain": "The card warns that vague answers score no marks — you must specify exactly what is expensive or involves paperwork, and explain the business-facing impact, as in the Companies House example given."}'::jsonb),
('business:1-3-business-ownership:misc:fa333b0f', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Once a business becomes a plc, it must remain a plc permanently.</p><p><strong>✅ The correct idea:</strong> Some businesses that became plcs have chosen to return to being private limited companies (''going private''). This can happen when owners want to regain control, protect themselves from hostile takeovers, or reduce the costs and public scrutiny associated with being a plc.</p>", "question": "Can a public limited company change back to being a private limited company?", "options": ["No — once a plc, it must remain a plc permanently", "No — a plc can only convert into a sole trader", "Yes, but only if ordered to by the Stock Exchange", "Yes — some plcs choose to ''go private'' to cut costs"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that plc status is permanent — some businesses ''go private'' again to regain control, avoid hostile takeovers, or cut the costs and scrutiny of being a plc."}'::jsonb),
('business:1-3-business-ownership:misc:b25b3798', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Unlimited liability is always a serious problem for sole traders and partners.</p><p><strong>✅ The correct idea:</strong> Unlimited liability is only a practical problem if the business fails and cannot pay its debts. Many successful sole traders and partners never face this issue during their careers. However, the RISK is always present — which is why limited liability is so attractive for businesses with significant financial exposure.</p>", "question": "When does unlimited liability actually become a practical problem for a sole trader or partner?", "options": ["Every single day the business is trading", "Only if the business fails and cannot pay its debts", "Only when the business first starts up", "Only if the business employs more than ten staff"]}'::jsonb, '{"answer": 1, "explain": "The card explains that unlimited liability is only a practical problem if the business fails and cannot pay its debts — many successful owners never face this issue, though the risk is always present."}'::jsonb),
('business:1-3-business-ownership:tips:8f119fd0', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Two Marks = One Point + One Development", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs exactly two things: a <strong>point</strong> and a <strong>development</strong>. Do not write a paragraph.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 (K):</strong> State the fact or concept clearly and correctly.</li>\n        <li><strong>Mark 2 (U):</strong> Develop it — explain what it means in practice or what the consequence is.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"Limited liability means the owner doesn''t have to pay all the debts.\"</em><br/>\n      Too vague — no development of what this actually means for the owner.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"With limited liability, shareholders can only lose up to the amount they originally invested in the company (K), meaning their personal possessions — such as their home — cannot be seized to repay business debts (U).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> The most common error on this question type is <strong>confusing limited liability with unlimited liability</strong> — describing owners'' possessions being TAKEN when explaining limited liability. This scores ZERO even if the rest of the answer appears correct. Always double-check your definition.</p>\n\n      <p><strong>🚫 The ''Explain'' Trap:</strong> The question says ''explain'', not ''identify''. If you just state \"limited liability means the owner is not responsible for all the debts\" without explaining what this means in practice, you will only score 1 mark, not 2.</p>\n    ", "question": "What must a 2-mark ''Explain'' answer contain to achieve full marks?", "options": ["Three separate advantages, briefly listed", "A definition followed by a real-world example only", "A correct point (K) plus its development (U)", "A conclusion stating the overall judgement"]}'::jsonb, '{"answer": 2, "explain": "The card''s formula for a 2-mark Explain question is one point (K) plus one development (U) — writing a full paragraph or just stating a fact without development will not achieve both marks."}'::jsonb),
('business:1-3-business-ownership:tips:73e95627', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark <strong>''Analyse''</strong> question requires all three assessment objectives in a logical chain. You will score <strong>ZERO for analysis</strong> if you do not apply it to the specific business in the case study.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State and explain the benefit or disadvantage clearly.<br/><em>e.g. \"Limited liability means shareholders only risk losing the amount they invested...\"</em></li>\n        <li><strong>Step 2 — Application (APP):</strong> Link directly to the case study business. Use their name and refer to specific details from the text.<br/><em>e.g. \"...which is important for Pen &amp; Sword Books, a family-owned business expanding into audio books...\"</em></li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line impact on the business — costs, revenue, growth, survival, or competitiveness.<br/><em>e.g. \"...meaning the family can invest confidently knowing they cannot lose more than their original stake, supporting the digital expansion.\"</em></li>\n      </ul>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about sole traders or partnerships. If the question asks for one advantage, give ONE advantage and develop it fully through all three steps. Three half-developed points score far fewer marks than one fully developed chain.</p>\n\n      <p><strong>The ''So What?'' Test for Analysis:</strong> Keep asking \"So what?\" until you reach a real business impact:</p>\n      <ul>\n        <li>\"Partnerships can raise more capital.\" → <em>So what?</em></li>\n        <li>\"This means the business has more money to invest.\" → <em>So what?</em></li>\n        <li>\"This increases the chances of the business surviving start-up and growing.\" ✅ AN mark earned.</li>\n      </ul>\n    ", "question": "What three elements must a 3-mark ''Analyse'' answer include to avoid scoring zero for analysis?", "options": ["Understanding, Application, and Analysis of impact", "Three different advantages listed one after another", "A definition, a diagram, and a conclusion", "Two advantages and one disadvantage"]}'::jsonb, '{"answer": 0, "explain": "The card''s ''Holy Trinity'' formula requires Understanding (U), Application to the specific case study business (APP), and Analysis of the bottom-line impact (AN) — without application to the named business, you score zero for analysis."}'::jsonb),
('business:1-3-business-ownership:tips:56aeff62', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two — 6 marks — 6 Marks = Two Separate 3-Mark Chains", "reading": "\n      <p>A 6-mark question asking you to <strong>''Analyse two...''</strong> is simply the 3-mark U → APP → AN formula done <strong>twice</strong>.</p>\n      <p><strong>Key Rules:</strong></p>\n      <ul>\n        <li>Clearly separate each point: label them <em>\"Disadvantage 1...\"</em> and <em>\"Disadvantage 2...\"</em></li>\n        <li><strong>Do NOT write a conclusion</strong> — there are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</li>\n        <li>Make sure both points are genuinely different — do not repeat the same idea in different words.</li>\n        <li>Both points must still be applied to the specific business in the case study to earn APP marks.</li>\n        <li><strong>The answer must relate to the legal status</strong> of the ownership type — not just general features of being a large or small business.</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Examiners reported that responses were \"often inaccurate or too vague\" on this question type. Vague answers like \"it costs more money\" or \"there is more paperwork\" will not score without specifying WHAT costs more money, WHY, and what the IMPACT is on the business.</p>\n\n      <p><strong>❌ Vague (scores 0-1 marks):</strong><br/>\n      <em>\"A disadvantage is that it costs a lot of money to run.\"</em></p>\n\n      <p><strong>✅ Full marks chain:</strong><br/>\n      <em>\"Shares in Shinz Ltd cannot be sold on the stock market (U). Even though Tom and Amir want to expand by launching a resin polish service (APP), this restriction limits the capital they can raise, potentially delaying their planned growth into this new market (AN).\"</em></p>\n    ", "question": "According to the card, what should you NOT include in a 6-mark ''Analyse two...'' answer?", "options": ["An application to the case study business", "A conclusion — no marks are available for it", "Two separate, clearly labelled points", "A development of each point"]}'::jsonb, '{"answer": 1, "explain": "The card states that a 6-mark ''Analyse two'' question has zero evaluation marks available, so writing a conclusion wastes time — instead you need two clearly separated U-APP-AN chains."}'::jsonb),
('business:1-3-business-ownership:tips:1aeaacbf', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — Structure Your Essay in 4 Clear Paragraphs", "reading": "\n      <p>A 9-mark <strong>''Evaluate''</strong> question tests ALL five assessment objectives. You need a structured response with <strong>four clear paragraphs</strong>. The examiner is looking for a <strong>justified judgement</strong> — not just a list of advantages and disadvantages.</p>\n\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K &amp; U:</strong> Define the key concept (e.g. what a sole trader is) and explain a relevant feature with its implication.</li>\n        <li><strong>Paragraph 2 — AN &amp; APP:</strong> Analyse a reason FOR the ownership type being suitable, using data and evidence from the case study.</li>\n        <li><strong>Paragraph 3 — AN &amp; APP:</strong> Analyse a reason AGAINST the ownership type being suitable, using data and evidence.</li>\n        <li><strong>Paragraph 4 — 3 Evaluation Points:</strong>\n          <ol>\n            <li>State your clear decision.</li>\n            <li>Contextualise it with specific data or facts from the case study.</li>\n            <li>Add a conditional point: \"However, this depends on whether...\"</li>\n          </ol>\n        </li>\n      </ul>\n\n      <p><strong>Sentence Starters for the Evaluation Paragraph:</strong></p>\n      <ul>\n        <li><em>\"Overall, I recommend that [business] should [decision] because...\"</em></li>\n        <li><em>\"Given that the data shows [specific figure or fact from the case study]...\"</em></li>\n        <li><em>\"However, this recommendation depends on whether [condition e.g. can secure a loan / find a suitable partner]...\"</em></li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> A conclusion that simply repeats your earlier analysis scores NO evaluation marks. You must make a judgement and justify it using specific case study context. The examiner''s report states evaluation must be <em>\"contextually robust\"</em> for the full 3 marks.</p>\n    ", "question": "In the 4-paragraph structure for a 9-mark ''Evaluate'' question, what must the final evaluation paragraph include to earn evaluation marks?", "options": ["A simple summary of the advantages and disadvantages already covered", "Three additional advantages not mentioned earlier", "A dictionary definition of the key term", "A clear decision, contextualised with case study data"]}'::jsonb, '{"answer": 3, "explain": "The card explains the evaluation paragraph needs three things: a clear decision, contextualisation with specific data/facts, and a conditional point — a conclusion that just repeats earlier analysis scores no evaluation marks."}'::jsonb),
('business:1-3-business-ownership:tips:3fd5dfb4', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Judgement + Comparison = Full Marks", "reading": "\n      <p>A 3-mark <strong>''Recommend''</strong> question requires three things: a <strong>clear decision</strong>, a <strong>reason for your choice</strong>, and a <strong>comparison with the alternative</strong>. You MUST address both options to earn the full justification marks.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 (Judgement):</strong> State your recommendation clearly. <em>e.g. \"Joe should become a sole trader.\"</em></li>\n        <li><strong>Marks 2–3 (Contextual Justification):</strong> Explain WHY your choice is BETTER THAN the other option, using specific details from the case study.</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> If you only explain why your chosen option is good WITHOUT explaining why it is better than the other option, you can only score a maximum of 1 justification mark. You MUST compare both options explicitly.</p>\n\n      <p><strong>✅ Model Starter:</strong><br/>\n      <em>\"Joe should become a sole trader (JUDGEMENT). Although a partnership with Mark would provide additional capital (acknowledge the other option), Joe already has £1,000 covering his first month''s costs, meaning he does not need Mark''s investment. As a sole trader, Joe keeps all profits and makes decisions without needing Mark''s agreement, allowing the barbers shop to respond quickly to customer demand (CONTEXTUAL JUSTIFICATION).\"</em></p>\n    ", "question": "What is required to earn full justification marks on a 3-mark ''Recommend'' question?", "options": ["Explaining why your choice beats the alternative option", "Simply stating your decision without giving any reason", "Listing every possible ownership type available", "Repeating the case study word for word"]}'::jsonb, '{"answer": 0, "explain": "The card warns that if you only explain why your chosen option is good without comparing it to the other option, you can score a maximum of 1 justification mark — you must explicitly compare both options."}'::jsonb),
