('business:1-4-business-aims-objectives:match:e96b7b51', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Business Objectives”?", "options": ["The financial reward for taking risk in business, calculated as revenue minus total costs.", "Making just enough profit to give the business owner a decent standard of living; common in small businesses.", "When a business becomes larger, for example by increasing sales, opening more outlets, or taking over a competitor.", "The goals a business aims to achieve, such as profit, survival, growth, market share, or providing a service."]}'::jsonb, '{"answer": 3, "explain": "“Business Objectives” means: The goals a business aims to achieve, such as profit, survival, growth, market share, or providing a service."}'::jsonb)
